const GRILLA_FILE = "Grilla 260126_Xtreme_Ultima.xlsx";
const ASIST_FILE  = "Asistencia.xlsx";
const SHEET_MO    = "MANO DE OBRA";
const TODOS       = "Todos";

// Logo embebido en base64 (PNG alta resolución)
const LOGO_B64 = "";

// Sindicato: fila 23-26 choferes de servicios con estos 3 identificados
const SINDICALISTAS = [
  "MARQUEZ SANCHEZ MANUEL",
  "PEREZ ZAMORANO FRANCISCO",
  "RAMOS ROJAS ÁLVARO",
  "RAMOS ROJAS ALVARO"
];

// Nombres femeninos en español para detección de género
const FEMALE_NAMES = new Set([
  "DANIELA","TERESA","BETZABE","BARBARA","KAREN","EVA","NICKOL","PIA",
  "VALENTINA","INGRID","IGNACIA","MARIA","JAVIERA","PAOLA","KATHERINE",
  "FRANSHESKA","LUCIA","ROSA","ANA","CARMEN","PATRICIA","ALEJANDRA",
  "ANDREA","CLAUDIA","LORENA","MARCELA","VERONICA","ISABEL","CRISTINA"
]);

// ─── SECCIONES DE LA GRILLA ─────────────────────────────────
// Fila (1-based en Excel):
// 5-6  : Jefes de Turno 1 y 2  → supervisor, compartido entre grupos
// 7-8  : Prevención APR 1 y 2
// 9    : Sala Control
// 11-15: Soporte Eléctrico
// 16   : Header DEPTO MECANICO
// 17-21: Depto Mecánico
// 22   : Bodegueros
// 23-26: Choferes de Servicio (3 de estos son sindicato)
// 27   : Header EQUIPOS MINERÍA
// 28-41: Operadores minería y oocc
// 43-48 : Cuadrilla 1 … (hasta fila 110)
// 111  : Header CUADRILLA MONTAJE
// 112-116: Cuadrilla Montaje (100% cubierta)
// 117-121: Adicionales

// ─── DATA STORES ────────────────────────────────────────────
let dataBase    = [];  // todos los registros filas 5-121
let dataSupport = [];  // filas 143-206
let dataSind    = [];  // sindicato derivado de grilla
let dataLM      = [];  // LM derivado de grilla
let dataAsist   = [];  // Asistencia.xlsx
let asistLoaded = false;
let todayColIdx = 17;  // índice JS (0-based) del día actual

const CH = {};

// ─── UTILS ──────────────────────────────────────────────────
const txt  = v => String(v ?? "").trim();
const up   = v => txt(v).toUpperCase();
const pct  = (n, d) => !d ? "–" : Math.round(n / d * 100) + "%";
const el   = id => document.getElementById(id);
const esV  = e => { const u = up(e); return u.startsWith("V") && u.length > 0; };

function normEst(e, l) {
  const eu = up(e), lu = up(l);
  if (lu === "L" || lu === "LM") return "LM";
  if (eu === "A")  return "A";
  if (eu === "P")  return "P";
  if (eu === "LM") return "LM";
  if (esV(eu))     return eu;
  return eu || "";
}

function isSind(nombre) {
  const un = up(nombre);
  return SINDICALISTAS.some(s => up(s).split(" ").some(w => w.length > 4 && un.includes(w)));
}

function inferGender(nombre) {
  const parts = up(nombre).split(/\s+/);
  for (let i = 2; i < parts.length; i++) {
    if (FEMALE_NAMES.has(parts[i])) return "M";
  }
  return "H";
}

function normTurno(t) {
  const u = up(t).replace(/\s/g,"");
  if (u.startsWith("7X7")) return "7x7";
  if (u.startsWith("5X2")) return "5x2";
  if (u.startsWith("8X6")) return "8x6";
  return txt(t) || "–";
}

function destroyCh(id) { if (CH[id]) { CH[id].destroy(); delete CH[id]; } }

const PAL = [
  "#3585e0","#3bba55","#e8a020","#c8302a","#9b68e0","#28c4b0",
  "#e86680","#d4971a","#4eb4e8","#56d364","#ff7b72","#d2a8ff",
  "#87c6ff","#ffa657","#7a8fa8"
];

function makeChart(id, type, labels, values, opts = {}) {
  destroyCh(id);
  const ctx = el(id);
  if (!ctx) return;
  const isXY = type !== "doughnut" && type !== "pie";
  CH[id] = new Chart(ctx, {
    type,
    data: {
      labels,
      datasets: [{
        label: opts.label || "Cantidad",
        data: values,
        backgroundColor: opts.colors || PAL,
        borderColor: "transparent",
        borderWidth: 1,
        borderRadius: type === "bar" ? 4 : 0
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: true,
      plugins: {
        legend: (type==="doughnut"||type==="pie")
          ? { display:true, position:"bottom", labels:{ color:"#7a8fa8", font:{size:10} } }
          : { display:false }
      },
      ...(isXY ? { scales: {
        x:{ ticks:{color:"#7a8fa8",font:{size:10}}, grid:{color:"#263045"} },
        y:{ ticks:{color:"#7a8fa8",font:{size:10}}, grid:{color:"#263045"} }
      }} : {}),
      ...(opts.extra || {})
    }
  });
}

function countBy(data, field) {
  return data.reduce((a,x)=>{ const k=txt(x[field])||"–"; a[k]=(a[k]||0)+1; return a; }, {});
}

function badge(e) {
  const u = up(e);
  if (u==="A")  return `<span class="badge ba-A">Acreditado</span>`;
  if (u==="P")  return `<span class="badge ba-P">En Proceso</span>`;
  if (u==="LM") return `<span class="badge ba-LM">LM</span>`;
  if (esV(u))   return `<span class="badge ba-V">${u||"Vacante"}</span>`;
  return `<span class="badge">${e}</span>`;
}

function fillTb(id, data, fn) {
  const tb = el(id);
  if (!tb) return;
  tb.innerHTML = "";
  data.forEach((x,i) => { const tr=document.createElement("tr"); tr.innerHTML=fn(x,i); tb.appendChild(tr); });
}

function setN(id, v) { const e=el(id); if(e) e.textContent=v; }

// ─── GAUGE ──────────────────────────────────────────────────
function drawGauge(cid, vid, ratio) {
  const cv = el(cid);
  if (!cv) return;
  cv.width=160; cv.height=90;
  const ctx = cv.getContext("2d");
  ctx.clearRect(0,0,160,90);
  const cx=80, cy=82, r=70;
  ctx.beginPath(); ctx.arc(cx,cy,r,Math.PI,2*Math.PI);
  ctx.strokeStyle="#263045"; ctx.lineWidth=13; ctx.lineCap="round"; ctx.stroke();
  const color = ratio>=.9?"#3bba55":ratio>=.7?"#d4971a":"#c8302a";
  ctx.beginPath(); ctx.arc(cx,cy,r,Math.PI,Math.PI+Math.PI*Math.min(ratio,1));
  ctx.strokeStyle=color; ctx.lineWidth=13; ctx.lineCap="round"; ctx.stroke();
  const ve=el(vid);
  if(ve){ve.textContent=Math.round(ratio*100)+"%"; ve.style.color=color;}
}

// ─── TAB NAV ────────────────────────────────────────────────
function switchTab(name) {
  document.querySelectorAll(".tab-content").forEach(t=>t.classList.remove("active"));
  document.querySelectorAll(".nav-item").forEach(n=>n.classList.remove("active"));
  el("tab-"+name)?.classList.add("active");
  document.querySelector(`.nav-item[data-tab="${name}"]`)?.classList.add("active");
  ({
    overview:   renderOverview,
    cuadrillas: renderCuadrillas,
    groups:     renderGroups,
    support:    renderSupport,
    asistencia: renderAsistencia,
    vacantes:   renderVacantes,
    detalle:    renderDetalle
  })[name]?.();
}

// ─── GLOBAL FILTERS ─────────────────────────────────────────
function getF() {
  return {
    grupo: el("filtroGrupo")?.value||TODOS,
    dept:  el("filtroDept")?.value||TODOS,
    turno: el("filtroTurno")?.value||TODOS,
    text:  up(el("buscarTexto")?.value||"")
  };
}

function applyF(data, f) {
  return data.filter(x => {
    const mt = !f.text || up(x.nombre).includes(f.text)||up(x.cargo).includes(f.text)||up(x.departamento).includes(f.text);
    const mg = f.grupo===TODOS || x.grupo===f.grupo;
    const md = f.dept ===TODOS || x.departamento===f.dept;
    const mk = f.turno===TODOS || normTurno(x.turno)===normTurno(f.turno);
    return mg&&md&&mk&&mt;
  });
}

function setOpts(sid, vals, sel=TODOS) {
  const s = el(sid);
  if(!s) return;
  const prev = s.value||sel;
  s.innerHTML = `<option value="${TODOS}">${TODOS}</option>`;
  [...new Set(vals.filter(v=>txt(v)))].sort((a,b)=>String(a).localeCompare(String(b),"es"))
    .forEach(v=>{ const o=document.createElement("option"); o.value=o.textContent=v; s.appendChild(o); });
  s.value = [...s.options].some(o=>o.value===prev) ? prev : TODOS;
}

function refreshCombos() {
  setOpts("filtroGrupo", ["GRUPO 1","GRUPO 2","GRUPO 3","GRUPO 4"]);
  setOpts("filtroDept",  [...new Set([...dataBase,...dataSupport].map(x=>x.departamento))]);
  setOpts("filtroTurno", [...new Set([...dataBase,...dataSupport].map(x=>normTurno(x.turno)))]);
}

// ─── OVERVIEW ───────────────────────────────────────────────
function renderOverview() {
  const f   = getF();
  const all = applyF([...dataBase,...dataSupport], f);
  const acr = all.filter(x=>x.estado==="A").length;
  const prc = all.filter(x=>x.estado==="P").length;
  const vac = all.filter(x=>esV(x.estado)).length;
  const tot = all.length;

  // Gender from grilla names
  let hom=0, muj=0;
  [...dataBase,...dataSupport].filter(x=>x.nombre&&up(x.nombre)!=="VACANTE")
    .forEach(x=>{ if(inferGender(x.nombre)==="M") muj++; else hom++; });
  const tG = hom+muj||1;

  // Sindicato = siempre 3 (identificados en SINDICALISTAS)
  const sindTot = 3;

  setN("kpiTotal",  tot);   setN("kpiAcred",   acr);   setN("kpiProc",    prc);
  setN("kpiVac",    vac);   setN("kpiHombres",  hom);   setN("kpiMujeres", muj);
  setN("kpiSind",   sindTot);
  setN("kpiAcredPct", pct(acr,tot)+" del total");
  setN("kpiProcPct",  pct(prc,tot)+" del total");
  setN("kpiVacPct",   pct(vac,tot)+" del total");
  setN("kpiHomPct",   pct(hom,tG)+" del total");
  setN("kpiMujPct",   pct(muj,tG)+" del total");

  // ── KPIs por Grupo (Turno 1,2,3,4) con % cobertura ──────
  ["GRUPO 1","GRUPO 2","GRUPO 3","GRUPO 4"].forEach((g,idx)=>{
    const n = idx+1;
    const gd  = dataBase.filter(x=>x.grupo===g);
    const ga  = gd.filter(x=>x.estado==="A").length;
    const gp  = gd.filter(x=>x.estado==="P").length;
    const gv  = gd.filter(x=>esV(x.estado)).length;
    const gt  = gd.length;
    const gpc = gt ? Math.round((ga+gp)/gt*100)+"%" : "–";
    setN(`kpiG${n}Pct`,  gpc);
    setN(`kpiG${n}Acred`,ga);
    setN(`kpiG${n}Vac`,  gv);
    setN(`kpiG${n}Tot`,  gt);
  });

  const b14 = applyF(dataBase, f);
  const rG  = tot ? (acr+prc)/tot : 0;
  const r14 = b14.length ? (b14.filter(x=>x.estado==="A").length+b14.filter(x=>x.estado==="P").length)/b14.length : 0;
  const rSp = dataSupport.length ? (dataSupport.filter(x=>x.estado==="A").length+dataSupport.filter(x=>x.estado==="P").length)/dataSupport.length : 0;
  const cuad = dataBase.filter(x=>x.fila>=43&&x.fila<=116);
  const rCu  = cuad.length ? (cuad.filter(x=>x.estado==="A").length+cuad.filter(x=>x.estado==="P").length)/cuad.length : 0;

  drawGauge("gCobertura","gvCobertura",rG);
  drawGauge("gGrupos",   "gvGrupos",   r14);
  drawGauge("gSoporte",  "gvSoporte",  rSp);
  drawGauge("gCuad",     "gvCuad",     rCu);

  const pg = countBy(all,"grupo");
  const pt = {};
  all.forEach(x=>{ const k=normTurno(x.turno); pt[k]=(pt[k]||0)+1; });
  makeChart("cGrupo",  "bar",      Object.keys(pg), Object.values(pg), {colors:["#3585e0","#3bba55","#e8a020","#c8302a","#9b68e0","#28c4b0"]});
  makeChart("cEstado", "doughnut", ["Acreditados","En Proceso","Vacantes"], [acr,prc,vac], {colors:["#3bba55","#d4971a","#c8302a"]});
  makeChart("cTurno",  "bar",      Object.keys(pt), Object.values(pt));
  makeChart("cGenero", "doughnut", ["Hombres","Mujeres"], [hom,muj], {colors:["#3585e0","#e86680"]});
}

// ─── CUADRILLAS ─────────────────────────────────────────────
// Cuadrillas 1-12: filas 43-110 (cuadrilla montaje: 112-116)
const CUAD_MAP = [
  {name:"CUADRILLA 1",      s:44,  e:48  },
  {name:"CUADRILLA 2",      s:50,  e:54  },
  {name:"CUADRILLA 3",      s:56,  e:60  },
  {name:"CUADRILLA 4",      s:62,  e:66  },
  {name:"CUADRILLA 5",      s:68,  e:71  },
  {name:"CUADRILLA 6",      s:73,  e:76  },
  {name:"CUADRILLA 7",      s:78,  e:81  },
  {name:"CUADRILLA 8",      s:83,  e:86  },
  {name:"CUADRILLA 9",      s:88,  e:92  },
  {name:"CUADRILLA 10",     s:94,  e:98  },
  {name:"CUADRILLA 11",     s:100, e:104 },
  {name:"CUADRILLA 12",     s:106, e:110 },
  {name:"CUADRILLA MONTAJE",s:112, e:116 }  // filas 112-116, 100% cubierta
];

function renderCuadrillas() {
  const gf = el("cuadGrupoSel")?.value||TODOS;
  // All cuadrilla data: rows 43-116
  let base = dataBase.filter(x=>x.fila>=43&&x.fila<=116);
  if (gf!==TODOS) base = base.filter(x=>x.grupo===gf);

  const tot = base.length;
  const acr = base.filter(x=>x.estado==="A").length;
  const prc = base.filter(x=>x.estado==="P").length;
  const vac = base.filter(x=>esV(x.estado)).length;

  setN("cuadTotal",tot); setN("cuadAcred",acr); setN("cuadProc",prc); setN("cuadVac",vac);
  setN("cuadPct", pct(acr+prc,tot));

  const pc = countBy(base,"cargo");
  const ps = Object.entries(pc).sort((a,b)=>b[1]-a[1]).slice(0,15);
  makeChart("cCuadCargo","bar",ps.map(x=>x[0]),ps.map(x=>x[1]),
    {extra:{indexAxis:"y",scales:{x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}},y:{ticks:{color:"#7a8fa8",font:{size:10}},grid:{color:"#263045"}}}}});

  const pt = {};
  base.forEach(x=>{ const k=normTurno(x.turno); pt[k]=(pt[k]||0)+1; });
  makeChart("cCuadTurno","bar",Object.keys(pt),Object.values(pt),{colors:PAL});

  const grid = el("cuadGrid");
  if(!grid) return;
  grid.innerHTML="";
  CUAD_MAP.forEach(c=>{
    let cd = dataBase.filter(x=>x.fila>=c.s&&x.fila<=c.e);
    if(gf!==TODOS) cd=cd.filter(x=>x.grupo===gf);
    if(!cd.length&&gf!==TODOS) return;
    const ca=cd.filter(x=>x.estado==="A").length;
    const cp=cd.filter(x=>x.estado==="P").length;
    const cv=cd.filter(x=>esV(x.estado)).length;
    const cov=cd.length?Math.round((ca+cp)/cd.length*100):0;
    // Montaje should show 100%
    const displayCov = (c.name==="CUADRILLA MONTAJE"&&cd.length>0&&cv===0) ? 100 : cov;
    const div=document.createElement("div");
    div.className="cuad-card";
    div.innerHTML=`<h4>${c.name}</h4>
      <div class="cst"><span>Total cargos</span><span>${cd.length}</span></div>
      <div class="cst"><span>Acreditados (A)</span><span class="c-green">${ca}</span></div>
      <div class="cst"><span>En proceso (P)</span><span class="c-yellow">${cp}</span></div>
      <div class="cst"><span>Vacantes</span><span class="c-red">${cv}</span></div>
      <div class="cst"><span>Cobertura</span><span style="color:var(--accent)">${displayCov}%</span></div>
      <div class="cbar"><div class="cbar-f" style="width:${displayCov}%"></div></div>`;
    grid.appendChild(div);
  });
}

// ─── GRUPOS 1-4 ─────────────────────────────────────────────
function renderGroups() {
  const f    = getF();
  const data = applyF(dataBase,f);

  // Independent KPI blocks
  const grid = el("grupoKPIs");
  if(grid) {
    grid.innerHTML="";
    ["GRUPO 1","GRUPO 2","GRUPO 3","GRUPO 4"].forEach(g=>{
      const gd  = dataBase.filter(x=>x.grupo===g);
      const tot = gd.length;
      const acr = gd.filter(x=>x.estado==="A").length;
      const prc = gd.filter(x=>x.estado==="P").length;
      const vac = gd.filter(x=>esV(x.estado)).length;
      // Jefe turno 1 from rows 5-6, APR from 7-8

      const div=document.createElement("div");
      div.className="gkblock";
      div.innerHTML=`<h4>${g}</h4>
        <div class="gkrow"><span>Total</span>       <strong>${tot}</strong></div>
        <div class="gkrow"><span>Acreditados</span> <strong class="c-green">${acr}</strong></div>
        <div class="gkrow"><span>En Proceso</span>  <strong class="c-yellow">${prc}</strong></div>
        <div class="gkrow"><span>Vacantes</span>    <strong class="c-red">${vac}</strong></div>
        <div class="gkrow"><span>% Cobertura</span> <strong style="color:var(--accent)">${pct(acr+prc,tot)}</strong></div>`;
      grid.appendChild(div);
    });
  }

  // Charts — turno agrupado
  const pt={};
  data.forEach(x=>{ const k=normTurno(x.turno); pt[k]=(pt[k]||0)+1; });
  const pc=countBy(data,"cargo");
  const ps=Object.entries(pc).sort((a,b)=>b[1]-a[1]).slice(0,15);
  makeChart("cCargo14","bar",ps.map(x=>x[0]),ps.map(x=>x[1]),
    {extra:{indexAxis:"y",scales:{x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}},y:{ticks:{color:"#7a8fa8",font:{size:10}},grid:{color:"#263045"}}}}});
  makeChart("cTurno14","bar",Object.keys(pt),Object.values(pt),{colors:["#3585e0","#3bba55","#e8a020","#c8302a"]});

  fillTb("tGrupos14",data,x=>`<td>${x.departamento}</td><td>${x.cargo}</td><td>${x.turno}</td><td>${x.grupo}</td><td>${x.nombre}</td><td>${badge(x.estado)}</td>`);
}

// ─── SOPORTE / ADMIN ────────────────────────────────────────
function renderSupport() {
  const dept  = el("suppDept")?.value||TODOS;
  const turno = el("suppTurno")?.value||TODOS;
  let data = dataSupport;
  if(dept!==TODOS)  data=data.filter(x=>x.departamento===dept);
  if(turno!==TODOS) data=data.filter(x=>normTurno(x.turno)===normTurno(turno));

  const tot=data.length, acr=data.filter(x=>x.estado==="A").length;
  const prc=data.filter(x=>x.estado==="P").length, vac=data.filter(x=>esV(x.estado)).length;

  setN("suppTotal",tot); setN("suppAcred",acr); setN("suppProc",prc); setN("suppVac",vac);
  setN("suppPct",pct(acr+prc,tot));

  const pc=countBy(data,"cargo");
  const ps=Object.entries(pc).sort((a,b)=>b[1]-a[1]);
  makeChart("cSuppCargo","bar",ps.map(x=>x[0]),ps.map(x=>x[1]),
    {extra:{indexAxis:"y",scales:{x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}},y:{ticks:{color:"#7a8fa8",font:{size:10}},grid:{color:"#263045"}}}}});
  const pt={};
  data.forEach(x=>{ const k=normTurno(x.turno); pt[k]=(pt[k]||0)+1; });
  makeChart("cSuppTurno","bar",Object.keys(pt),Object.values(pt),{colors:PAL});

  fillTb("tSoporte",data,x=>`<td>${x.departamento}</td><td>${x.cargo}</td><td>${x.turno}</td><td>${x.nombre}</td><td>${badge(x.estado)}</td>`);
}

// ─── SINDICATO (derivado de grilla, sin hoja separada) ───────
function renderSindicato() {
  const sind = dataSind.filter(x=>x.tipo==="SIND");
  const lm   = dataSind.filter(x=>x.tipo==="LM");
  setN("sindCount",sind.length); setN("lmCount",lm.length); setN("totalAfect",dataSind.length);

  makeChart("cSindLM","doughnut",["Sindicato","Licencia Médica"],[sind.length,lm.length],{colors:["#28c4b0","#9b68e0"]});
  const pc=countBy(lm,"cargo");
  makeChart("cCargoLM","bar",Object.keys(pc),Object.values(pc),
    {colors:["#9b68e0"],extra:{indexAxis:"y",scales:{x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}},y:{ticks:{color:"#7a8fa8",font:{size:10}},grid:{color:"#263045"}}}}});

  fillTb("tSind",sind,(x,i)=>`<td>${i+1}</td><td>${x.cargo}</td><td>${x.nombre}</td><td><span class="badge ba-SN">SIND</span></td>`);
  fillTb("tLM",  lm,  (x,i)=>`<td>${i+1}</td><td>${x.cargo}</td><td>${x.nombre}</td><td><span class="badge ba-LM">LM</span></td>`);
}

// ─── ASISTENCIA ─────────────────────────────────────────────
function renderAsistencia() {
  if(!asistLoaded){ setN("asistFecha","Asistencia.xlsx no encontrado"); return; }

  const tf = el("asiTurnoFiltro")?.value||TODOS;
  const gf = el("asiGrupoFiltro")?.value||TODOS;

  let data = dataAsist;
  if(tf!==TODOS) data=data.filter(x=>normTurno(x.turno)===normTurno(tf));
  if(gf!==TODOS) data=data.filter(x=>up(x.grupo).includes(up(gf).replace("GRUPO ","G").trim())||up(x.grupo)===up(gf));

  // ── Resumen mensual acumulado desde columnas de resumen ──
  // Índices JS 0-based: 45=TurnoA, 46=TurnoB, 50=Descansos, 51=FALLAS, 52=LICENCIAS, 54=PS, 56=VAC, 57=IMM
  const lmList   = data.filter(x=>x.lmDias>0);
  const fList    = data.filter(x=>x.fallas>0);
  const psList   = data.filter(x=>x.psDias>0);
  const vacList  = data.filter(x=>x.vacDias>0);
  const immList  = data.filter(x=>x.immDias>0);
  const diasLM   = lmList.reduce((s,x)=>s+x.lmDias,0);
  const turnoATot= data.reduce((s,x)=>s+x.turnoA,0);
  const turnoBTot= data.reduce((s,x)=>s+x.turnoB,0);
  const descTot  = data.reduce((s,x)=>s+x.descansos,0);

  setN("asiTotal",    data.length);
  setN("asiTurnoA",   turnoATot);
  setN("asiTurnoB",   turnoBTot);
  setN("asiDescansos",descTot);
  setN("asiLM",       lmList.length);
  setN("asiFallas",   fList.length);
  setN("asiPS",       psList.length);
  setN("asiVac",      vacList.length);
  setN("asiIMM",      immList.length);
  setN("asiDiasLM",   diasLM);

  // ── Chart: mensual por grupo ─────────────────────────────
  const byGrupo = {};
  data.forEach(x=>{
    const g = up(x.grupo)||"SIN GRUPO";
    if(!byGrupo[g]) byGrupo[g]={A:0,D:0,LM:0,F:0,PS:0};
    byGrupo[g].A  += x.turnoA||0;
    byGrupo[g].D  += x.descansos||0;
    byGrupo[g].LM += x.lmDias||0;
    byGrupo[g].F  += x.fallas||0;
    byGrupo[g].PS += x.psDias||0;
  });

  const grpLbls   = Object.keys(byGrupo).sort();
  const dsActivo   = {label:"Turno A+B",  data:grpLbls.map(g=>byGrupo[g].A),  backgroundColor:"#3bba55", borderRadius:4};
  const dsDescanso = {label:"Descanso",   data:grpLbls.map(g=>byGrupo[g].D),  backgroundColor:"#7a8fa8", borderRadius:4};
  const dsLM       = {label:"LM (días)",  data:grpLbls.map(g=>byGrupo[g].LM), backgroundColor:"#9b68e0", borderRadius:4};
  const dsF        = {label:"Fallas",     data:grpLbls.map(g=>byGrupo[g].F),  backgroundColor:"#c8302a", borderRadius:4};
  const dsPS       = {label:"PS (días)",  data:grpLbls.map(g=>byGrupo[g].PS), backgroundColor:"#28c4b0", borderRadius:4};

  destroyCh("cAsiGrupo");
  const ctx=el("cAsiGrupo");
  if(ctx){
    CH["cAsiGrupo"]=new Chart(ctx,{
      type:"bar",
      data:{ labels:grpLbls, datasets:[dsActivo,dsDescanso,dsLM,dsF,dsPS] },
      options:{
        responsive:true, maintainAspectRatio:true,
        plugins:{ legend:{display:true,position:"bottom",labels:{color:"#7a8fa8",font:{size:10}}} },
        scales:{ x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}}, y:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}} }
      }
    });
  }

  const pt={};
  data.forEach(x=>{ const k=normTurno(x.turno); pt[k]=(pt[k]||0)+1; });
  makeChart("cAsiTurno","bar",Object.keys(pt),Object.values(pt),{colors:["#3585e0","#3bba55","#e8a020"]});

  fillTb("tAsiLM",    lmList.sort((a,b)=>b.lmDias-a.lmDias),  x=>`<td>${x.nombre}</td><td>${x.cargo}</td><td>${x.grupo}</td><td><strong class="c-purple">${x.lmDias}</strong></td>`);
  fillTb("tAsiPS",    psList.sort((a,b)=>b.psDias-a.psDias),   x=>`<td>${x.nombre}</td><td>${x.cargo}</td><td>${x.grupo}</td><td><strong class="c-teal">${x.psDias}</strong></td>`);
  fillTb("tAsiFallas",fList.sort((a,b)=>b.fallas-a.fallas),    x=>`<td>${x.nombre}</td><td>${x.cargo}</td><td>${x.grupo}</td><td><strong class="c-red">${x.fallas}</strong></td>`);
}

// ─── VACANTES ───────────────────────────────────────────────
function renderVacantes() {
  const filtroC=el("vacCargo")?.value||TODOS;
  const filtroG=el("vacGrupo")?.value||TODOS;

  const vB=dataBase.filter(x=>esV(x.estado)).map(x=>({...x,origen:"Grupos 1–4"}));
  const vS=dataSupport.filter(x=>esV(x.estado)).map(x=>({...x,origen:"Soporte/Admin",grupo:"SOPORTE"}));
  let all=[...vB,...vS];
  if(filtroG!==TODOS) all=all.filter(x=>x.grupo===filtroG);
  setOpts("vacCargo",all.map(x=>x.cargo),filtroC);
  if(filtroC!==TODOS) all=all.filter(x=>x.cargo===filtroC);

  setN("vacTotal",  [...vB,...vS].length);
  setN("vacGrupos", vB.length);
  setN("vacSoporte",vS.length);
  setN("vacCargos", new Set([...vB,...vS].map(x=>x.cargo)).size);

  const pc=countBy(all,"cargo");
  const ps=Object.entries(pc).sort((a,b)=>b[1]-a[1]);
  makeChart("cVacCargo","bar",ps.map(x=>x[0]),ps.map(x=>x[1]),{colors:["#c8302a"],extra:{indexAxis:"y",scales:{x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}},y:{ticks:{color:"#7a8fa8",font:{size:10}},grid:{color:"#263045"}}}}});
  const pd=countBy(all,"departamento");
  const pds=Object.entries(pd).sort((a,b)=>b[1]-a[1]);
  makeChart("cVacDept","bar",pds.map(x=>x[0]),pds.map(x=>x[1]),{colors:["#9b68e0"],extra:{indexAxis:"y",scales:{x:{ticks:{color:"#7a8fa8"},grid:{color:"#263045"}},y:{ticks:{color:"#7a8fa8",font:{size:10}},grid:{color:"#263045"}}}}});
  fillTb("tVacantes",all,x=>`<td><span class="badge ba-ORIG">${x.origen}</span></td><td>${x.departamento||"–"}</td><td>${x.cargo}</td><td>${x.turno||"–"}</td><td>${x.grupo||"–"}</td><td>${badge(x.estado)}</td>`);
}

// ─── DETALLE ────────────────────────────────────────────────
// dataDetalle: registros con col de grupo exacta (filas 5-121)
// Cada fila tiene exactamente 1 persona por grupo → mostramos todas
function renderDetalle() {
  const grupo = el("detGrupo")?.value || "GRUPO 1";
  const cargo = el("detCargo")?.value || TODOS;

  // Obtener SOLO los registros de este grupo (ya filtrados en dataBase)
  const gdata = dataBase.filter(x => x.grupo === grupo);

  // Poblar selector de cargos con los únicos del grupo
  setOpts("detCargo", gdata.map(x => x.cargo), cargo);
  const data = cargo === TODOS ? gdata : gdata.filter(x => x.cargo === cargo);

  // KPIs correctos para este grupo específico
  const acr = data.filter(x => x.estado === "A").length;
  const prc = data.filter(x => x.estado === "P").length;
  const vac = data.filter(x => esV(x.estado)).length;
  const tot = data.length;

  const kd = el("detKPIs");
  if (kd) kd.innerHTML = `
    <div class="km"><span class="kml">Total Cargos</span>   <strong>${tot}</strong></div>
    <div class="km"><span class="kml">Acreditados (A)</span> <strong class="c-green">${acr}</strong></div>
    <div class="km"><span class="kml">En Proceso (P)</span>  <strong class="c-yellow">${prc}</strong></div>
    <div class="km c-red"><span class="kml">Vacantes</span>  <strong>${vac}</strong></div>
    <div class="km"><span class="kml">% Cobertura</span>     <strong class="c-green">${pct(acr+prc,tot)}</strong></div>`;

  // Tabla con todos los cargos del grupo, ordenados por sección/fila
  const sorted = [...data].sort((a, b) => a.fila - b.fila);
  fillTb("tDetalle", sorted, x => {
    const esVac = esV(x.estado);
    const rowClass = esVac ? ' style="background:rgba(200,48,42,.07)"' : '';
    return `<tr${rowClass}>
      <td>${x.departamento}</td>
      <td>${x.cargo}</td>
      <td>${x.turno}</td>
      <td>${esVac ? '<em style="color:var(--red)">— VACANTE —</em>' : x.nombre}</td>
      <td>${badge(x.estado)}</td>
    </tr>`.replace('<tr>', '').replace('</tr>', '');
  });
}

// ─── LOAD GRILLA ────────────────────────────────────────────
async function loadGrilla() {
  const resp=await fetch(GRILLA_FILE);
  if(!resp.ok) throw new Error("No se encontró "+GRILLA_FILE);
  const buf=await resp.arrayBuffer();
  const wb=XLSX.read(buf,{type:"array"});
  const ws=wb.Sheets[SHEET_MO];
  const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:""});

  // Secciones a excluir (headers de sección, no registros de personas)
  const EXCL=new Set([
    "SUPERVISIÓN","SOPORTE OPERACIÓN","DEPTO MECANICO","EQUIPOS MINERÍA Y OOCC",
    "SOPORTE MECANICO","SERVICIO","OPERACIONES","OFICINA TÉCNICA",
    "SEGURIDAD Y MEDIO AMBIENTE","RELACIONES LABORALES","ÁREA ELÉCTRICA",
    "ÁREA ABASTECIMIENTO Y LOGÍSTICA","CUADRILLA 1","CUADRILLA 2","CUADRILLA 3",
    "CUADRILLA 4","CUADRILLA 5","CUADRILLA 6","CUADRILLA 7","CUADRILLA 8",
    "CUADRILLA 9","CUADRILLA 10","CUADRILLA 11","CUADRILLA 12","CUADRILLA MONTAJE"
  ]);

  const isOK = (dep,cargo) => {
    if(!txt(cargo)) return false;
    if(EXCL.has(up(cargo))||EXCL.has(up(dep))) return false;
    // Exclude row 4 (header row) and row 117 (ADICIONALES)
    return true;
  };

  dataBase=[]; dataSind=[]; dataLM=[];

  // ── FILAS 5-121 (índice 4-120) ──────────────────────────
  for(let i=4; i<=120&&i<rows.length; i++){
    const row=rows[i];
    const dep=txt(row[1]), cargo=txt(row[2]), turno=txt(row[3]);
    if(!isOK(dep,cargo)) continue;
    // Fila 117 = ADICIONALES header, skip
    if(i+1===117) continue;

    const GS=[
      {grupo:"GRUPO 1",n:row[4], e:row[5], l:""},
      {grupo:"GRUPO 2",n:row[6], e:row[7], l:row[8]},
      {grupo:"GRUPO 3",n:row[9], e:row[10],l:row[11]},
      {grupo:"GRUPO 4",n:row[12],e:row[13],l:""}
    ];

    GS.forEach(g=>{
      const nm=txt(g.n), st=normEst(g.e,g.l);
      if(!nm&&!st) return;
      const nombre=nm||"VACANTE";
      const rec={fila:i+1, departamento:dep, cargo, turno, grupo:g.grupo, estado:st, nombre};
      dataBase.push(rec);

      // Detectar LM en la grilla
      if(st==="LM"){
        dataLM.push({cargo,nombre,tipo:"LM",grupo:g.grupo,fuente:"Grilla"});
      }
      // Detectar sindicato: choferes de servicio en filas 23-26 con nombres identificados
      if(nombre!=="VACANTE"&&isSind(nombre)){
        if(!dataSind.find(s=>up(s.nombre)===up(nombre))){
          dataSind.push({cargo,nombre,tipo:"SIND",grupo:g.grupo});
        }
      }
    });
  }

  // ── FILAS 143-206 (soporte/admin) ───────────────────────
  dataSupport=[];
  for(let i=142; i<=205&&i<rows.length; i++){
    const row=rows[i];
    const dep=txt(row[1]), cargo=txt(row[2]), turno=txt(row[3]);
    if(!dep||!cargo||EXCL.has(up(cargo))) continue;

    const add=(ni,ei,li="")=>{
      const nm=txt(row[ni]), st=normEst(txt(row[ei]),txt(li?row[parseInt(li)]:"")||"");
      if(!nm&&!st) return;
      const e=st||(nm&&up(nm)!=="VACANTE"?"A":"V");
      const nombre=nm||"VACANTE";
      dataSupport.push({fila:i+1,departamento:dep,cargo,turno:turno||"5X2",grupo:"SOPORTE",estado:e,nombre});

      // Choferes camion: filas 155-159
      if(i+1>=155&&i+1<=159){
        // already included in dataSupport, label section
      }
    };
    add(4,13);
    if(txt(row[6])&&txt(row[6])!==txt(row[4])) add(6,7);
    if(txt(row[9])&&txt(row[9])!==txt(row[4])&&txt(row[9])!==txt(row[6])) add(9,10);
  }

  // Merge LM from grilla into dataSind list
  dataLM.forEach(x=>{
    if(!dataSind.find(s=>up(s.nombre)===up(x.nombre)&&s.tipo==="LM")){
      dataSind.push(x);
    }
  });

  refreshCombos();
  setOpts("suppDept",dataSupport.map(x=>x.departamento));
}

// ─── LOAD ASISTENCIA ────────────────────────────────────────
async function loadAsistencia() {
  try {
    const resp=await fetch(ASIST_FILE);
    if(!resp.ok){ asistLoaded=false; return; }
    const buf=await resp.arrayBuffer();
    const wb=XLSX.read(buf,{type:"array"});
    const ws=wb.Sheets[wb.SheetNames[0]];
    const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:""});

    // Row 6 (index 5): col 16 (index 15) = day 1, col 17 (index 16) = day 2, col 18 (index 17) = day 3
    // Find today = last day col with substantial data (>50 entries)
    let todayIdx=17; // default = day 3, index 17 (col 18)
    for(let ci=15; ci<=45; ci++){
      const cnt=rows.slice(6).filter(r=>r[ci]&&String(r[ci]).trim()).length;
      if(cnt>50) todayIdx=ci;
    }
    todayColIdx=todayIdx;
    const dayNum=rows[5]?.[todayIdx];

    dataAsist=[];
    for(let i=6; i<rows.length; i++){
      const r=rows[i];
      const ap1=txt(r[2]);
      if(!ap1||ap1==="APELLIDO PATERNO") continue;
      const ap2=txt(r[3]), nom=txt(r[4]);
      const nombre=`${ap1} ${nom}`.trim();
      if(!nombre||nombre.length<3) continue;

      const cargo    = txt(r[5]);
      const grupo    = txt(r[10]);
      const sexo     = txt(r[12]);
      const turno    = txt(r[14]);
      // Summary columns (0-based in JS array):
      // col46=turnoA→idx45, col47=turnoB→idx46, col51=descansos→idx50
      // col52=FALLAS→idx51, col53=LICENCIAS→idx52
      // col55=PS→idx54, col57=VAC→idx56, col58=IMM→idx57
      const turnoA   = Number(r[45])||0;
      const turnoB   = Number(r[46])||0;
      const descansos= Number(r[50])||0;
      const fallas   = Number(r[51])||0;
      const lmDias   = Number(r[52])||0;
      const psDias   = Number(r[54])||0;
      const vacDias  = Number(r[56])||0;
      const immDias  = Number(r[57])||0;
      const todayCode= txt(r[todayIdx]).toUpperCase();

      dataAsist.push({nombre,cargo,grupo,sexo,turno,turnoA,turnoB,descansos,fallas,lmDias,psDias,vacDias,immDias,todayCode});
    }

    // Set fecha badge
    const fe=el("asistFecha");
    if(fe) fe.textContent=`Día ${dayNum||"?"} — Abril 2026`;

    asistLoaded=true;
  } catch(e) {
    asistLoaded=false;
    console.warn("Asistencia:",e.message);
  }
}

// ─── INIT ───────────────────────────────────────────────────
async function init(){
  const logo=el("logoImg");
  if(logo) logo.src="data:image/png;base64,"+LOGO_B64;

  const stat=el("statusBox");
  try {
    stat.textContent="Cargando grilla…";
    await loadGrilla();
    stat.textContent="Cargando asistencia…";
    await loadAsistencia();
    stat.textContent=`✓ ${dataBase.length+dataSupport.length} registros · ${asistLoaded?"Asistencia OK":"Sin asistencia"}`;
    renderOverview();

    // Header filters
    ["filtroGrupo","filtroDept","filtroTurno"].forEach(id=>{
      el(id)?.addEventListener("change",()=>{
        const a=document.querySelector(".tab-content.active")?.id?.replace("tab-","");
        if(a) switchTab(a);
      });
    });
    el("buscarTexto")?.addEventListener("input",()=>{
      const a=document.querySelector(".tab-content.active")?.id?.replace("tab-","");
      if(a) switchTab(a);
    });
    el("btnLimpiar")?.addEventListener("click",()=>{
      el("buscarTexto").value="";
      ["filtroGrupo","filtroDept","filtroTurno"].forEach(id=>{const s=el(id);if(s)s.value=TODOS;});
      const a=document.querySelector(".tab-content.active")?.id?.replace("tab-","");
      if(a) switchTab(a);
    });

    // Tab filters
    el("cuadGrupoSel")?.addEventListener("change",renderCuadrillas);
    el("suppDept")?.addEventListener("change",renderSupport);
    el("suppTurno")?.addEventListener("change",renderSupport);
    el("vacCargo")?.addEventListener("change",renderVacantes);
    el("vacGrupo")?.addEventListener("change",renderVacantes);
    el("detGrupo")?.addEventListener("change",()=>{ el("detCargo").value=TODOS; renderDetalle(); });
    el("detCargo")?.addEventListener("change",renderDetalle);
    el("asiTurnoFiltro")?.addEventListener("change",renderAsistencia);
    el("asiGrupoFiltro")?.addEventListener("change",renderAsistencia);

  } catch(err){
    console.error(err);
    stat.textContent="⚠ Error: "+err.message;
  }
}

document.addEventListener("DOMContentLoaded",init);